WHERE NOT EXISTS (
  SELECT 1 FROM race_catalog c
  WHERE lower(c.name) = lower(v.name::text)
    AND lower(c.city) = lower(v.city::text)
    AND c.year = v.year::int
    AND ROUND(c.dist_km::numeric, 1) = ROUND(v.dist_km::numeric, 1)
);

